#include<iostream>#include<string> using namespace std; int main(){    int t;    cin >> t;     while(t--){        int n;        cin >> n;         string s;        cin >> s;         int count = 0;        bool hasTriple = false;         for (int i = 0; i < n; i++) {            if (s[i] == '.') {                count++;                if (i > 0 && i < n - 1 && s[i - 1] == '.' && s[i + 1] == '.') {                    hasTriple = true;                }            }        }         if (hasTriple) cout << 2 << "\n";        else cout << count << "\n";    }    return 0;}